module RefModule(
  input [3:0] A,
  input [3:0] B,
  input Sub,
  input clk,
  output reg [3:0] result  // Change wire to reg for result
);wire [3:0] add_result;
  wire [3:0] sub_result;

  // Adder logic
    wire _n01 = A[0] ^ B[0];
  wire _c01 = A[0] & B[0];
  wire _n02 = A[1] ^ B[1] ^ _c01;
  wire _c02 = (A[1] & B[1]) | (A[1] & _c01) | (B[1] & _c01);
  wire _n03 = A[2] ^ B[2] ^ _c02;
  wire _c03 = (A[2] & B[2]) | (A[2] & _c02) | (B[2] & _c02);
  wire _n04 = A[3] ^ B[3] ^ _c03;
  wire _c04 = (A[3] & B[3]) | (A[3] & _c03) | (B[3] & _c03);
  assign add_result = {_n01, _n02, _n03, _n04};

  // Subtractor logic
  assign sub_result = A - B;

  // Result selection logic
  always @ (posedge clk) begin
    if (Sub == 1'b0) begin
      result <= add_result;
    end else begin
      result <= sub_result;
    end
  end

endmodule
